class Solution(object):
    def canArrange(self, arr, k):
        from collections import Counter
        cnt = Counter(x % k for x in arr)
        for r in list(cnt.keys()):
            if r == 0:
                if cnt[r] % 2 != 0:
                    return False
            else:
                if cnt[r] != cnt.get(k - r, 0):
                    return False
        return True
